import { memoize } from 'lodash-es';

import { SCALE_FALLBACK_COLOR } from '../../../constants.js';
import { getTokenComputedStyle } from '../../../utils/getTokenComputedStyle.js';
import { isValidCSSColor } from '../../../utils/getValidColor.js';

/**
 * Transforms the color to be used in a canvas. If it's a token,
 * gets the HSL color, otherwise returns the color or the default one
 * if undefined.
 *
 * @internal
 * @param color - The color to be transformed.
 * @param fallbackColor - The color to be applied if transformation fails. Default: Colors.Background.Container.Neutral.Accent
 */
export const getCanvasColor: (
  color: string | undefined,
  fallbackColor?: string,
) => string = memoize(
  (color: string | undefined, fallbackColor = SCALE_FALLBACK_COLOR): string => {
    let transformedColor = color ?? fallbackColor;

    if (transformedColor.indexOf('var') >= 0) {
      transformedColor = getTokenComputedStyle(transformedColor);

      return transformedColor
        ? transformedColor
        : getTokenComputedStyle(fallbackColor);
    }

    if (!isValidCSSColor(transformedColor)) {
      return getTokenComputedStyle(fallbackColor);
    }

    return transformedColor;
  },
);
